scwin.f_RetrieveShiftingResults = async function () {
  if (!(await $c.gus.cfValidate($p, [ed_cvsslMgntNo]))) return;
  dma_condition.set("cvsslMgntNo", ed_cvsslMgntNo.getValue());
  dma_caculateShiftingSelling.set("ctrtNo", "");
  dma_caculateShiftingSelling.set("selpchItemCd", "");
  dma_caculateShiftingSelling.set("crcCd", "");
  dma_caculateShiftingSelling.set("ctrtTrf", "");
  dma_caculateShiftingSelling.set("ctrtTrfFcrc", "");
  dma_caculateShiftingSelling.set("unitCd", "");
  dma_caculateShiftingSelling.set("unitClsCd", "");
  dma_caculateShiftingSelling.set("ctrtWrkPathSeq", "");
  dma_caculateShiftingSelling.set("unitNm", "");
  dma_caculateShiftingSelling.set("stdDt", "");
  await $c.sbm.execute($p, sbm_condition);
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    dma_caculateShiftingSelling.set("ctrtNo", "");
    dma_caculateShiftingSelling.set("selpchItemCd", "");
    dma_caculateShiftingSelling.set("crcCd", ds_cargoShiftingResults.getCellData(i, "crcCd"));
    dma_caculateShiftingSelling.set("ctrtTrf", "");
    dma_caculateShiftingSelling.set("ctrtTrfFcrc", "");
    dma_caculateShiftingSelling.set("unitCd", "");
    dma_caculateShiftingSelling.set("unitClsCd", "");
    dma_caculateShiftingSelling.set("ctrtWrkPathSeq", "");
    dma_caculateShiftingSelling.set("unitNm", "");
    dma_caculateShiftingSelling.set("stdDt", ds_carryingVesselCompletionInformation.getCellData(0, "cvsslWrkCompleteDt"));
    await $c.sbm.execute($p, sbm_ExchRate);
    ds_cargoShiftingResults.setCellData(i, "stdExchRt", ds_ExchRate.getCellData(0, "stdExchRt"));
  }
};
