scwin.f_Round = async function (Num, Position, Base) {
  if (Position == 0) {
    return Math.round(Num);
  } else if (Position > 0) {
    let cipher = '1';
    for (let i = 0; i < Position; i++) cipher = cipher + '0';
    let no = Number(cipher);
    if (Base == "F") {
      return Math.round(Num * no) / no;
    } else {
      return Math.round(Num / no) * no;
    }
  } else {
    await $c.win.alert($p, "자릿수는 정수로만 구분합니다.");
    return false;
  }
};
scwin.f_Save = async function () {
  let count = 0;
  let count1 = 0;
  let chg = 0;
  let hodrNo = "";
  let delcount = 0;
  for (let i = 0; i < ds_caculateShiftingSellingHidden1.getRowCount(); i++) {
    for (let j = 0; j < ds_cargoShiftingResults.getRowCount(); j++) {
      if (ds_cargoShiftingResults.getCellData(j, "chk") == "T") {
        if (ds_cargoShiftingResults.getCellData(j, "adptQty") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptQty") || ds_cargoShiftingResults.getCellData(j, "adptWt") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptWt") || ds_cargoShiftingResults.getCellData(j, "adptCbm") != ds_caculateShiftingSellingHidden1.getCellData(i, "adptCbm") || ds_cargoShiftingResults.getCellData(j, "sellAmtFcrc") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellAmtFcrc") || ds_cargoShiftingResults.getCellData(j, "sellAmt") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellAmt") || ds_cargoShiftingResults.getCellData(j, "sellCtrlAmtFcrc") != ds_caculateShiftingSellingHidden1.getCellData(i, "sellCtrlAmtFcrc")) {
          ds_cargoShiftingResults.setCellData(j, "commNm", ds_caculateShiftingSellingHidden1.getCellData(i, "commNm") + " ");
          chg++;
        }
      }
    }
  }
  if (!(await $c.gus.cfValidate($p, [gr_cargoShiftingResults]))) {
    return;
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getCellData(i, "selpchItemCd") == "") {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["매출항목"]);
      return false;
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getCellData(i, "chk") == "T") {
      count++;
      break;
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getRowStatus(i) == "D") {
      count1++;
      break;
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getRowStatus(i) == "C" && scwin.count2 == 0) {
      scwin.count3++;
      break;
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getCellData(i, "chk") == "T") {
      if (ds_cargoShiftingResults.getCellData(i, "ctrtTrf") == 0) {
        await $c.gus.cfAlertMsg($p, i + 1 + "번째 데이터의 계약요율이 존재하지 않으므로 " + (i + 1) + "번째 데이터는 저장할수가 없습니다.");
        ds_cargoShiftingResults.setCellData(i, "chk", "F");
        scwin.count3 = 0;
        scwin.count2++;
        return false;
      }
    }
  }
  if (chg == 0 && scwin.count3 == 0 && count1 == 0) {
    for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
      if (ds_cargoShiftingResults.getCellData(i, "chk") == "F") {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ["수정할 데이터의 체크박스"]);
        return false;
      } else {
        await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["SHIFTING 매출"]);
        return false;
      }
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getCellData(i, "sellClsCd") == "N") {
      ds_cargoShiftingResults.setRowStatus(i, "C");
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getCellData(i, "chk") == "T" && ds_cargoShiftingResults.getCellData(i, "adptQty") == 0 && ds_cargoShiftingResults.getCellData(i, "adptWt") == 0 && ds_cargoShiftingResults.getCellData(i, "adptCbm") == 0 && ds_cargoShiftingResults.getCellData(i, "sellCtrlAmtFcrc") == 0) {
      await $c.win.alert($p, i + 1 + "번째 데이터는 변경된 사항이 없습니다. 선택된 체크박스를 해제해 주십시오.");
      return false;
    }
  }
  for (let i = 0; i < ds_cargoShiftingResults.getRowCount(); i++) {
    if (ds_cargoShiftingResults.getRowStatus(i) == "D") {
      delcount = delcount + 1;
    }
  }
  if (count == 0 && count1 == 0) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, ["수정할 데이터의 체크박스"]);
    return false;
  } else {
    if (delcount != ds_cargoShiftingResults.getRowCount()) {
      let chk = await $c.win.confirm($p, "선택된 데이터만 저장이 가능합니다.저장하시겠습니까?");
      if (chk) {
        await $c.sbm.execute($p, sbm_save);
      }
    } else {
      let chk = await $c.win.confirm($p, "저장하시겠습니까?");
      if (chk) {
        await $c.sbm.execute($p, sbm_save);
      }
    }
  }
};
