scwin.f_grdHeiht = function (objGrdId, size) {
  // TODO: 동적 그리드 높이 조정 — WebSquare에서 별도 처리 필요
  let objGrd = $p.getComponentById(objGrdId);
  if (objGrd) {
    let strHeight = objGrd.getStyle("height");
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
      objGrd.setStyle("height", intHeight + "px");
    }
  }
  let strHeight2 = gr_ShiftingResults.getStyle("height");
  let intHeight2 = parseInt(strHeight2.replace("px", ""));
  intHeight2 = intHeight2 + size;
  if (intHeight2 > 0) {
    gr_ShiftingResults.setStyle("height", intHeight2 + "px");
  }
};
